let raw = $input.first().json;
let body = raw;
if (raw && raw.body !== undefined) body = raw.body;
else if (raw && raw.data !== undefined) body = raw.data;
if (typeof body === 'string') { try { body = JSON.parse(body); } catch (e) {} }
const defs = (body && (body.definitions || (body.components && body.components.schemas))) || {};
const tableMap = {}; const lines = [];
for (const t of Object.keys(defs)) {
  const props = (defs[t] && defs[t].properties) ? Object.keys(defs[t].properties) : [];
  tableMap[t] = props;
  lines.push(t + '(' + props.join(', ') + ')');
}
return [{ json: { schemaText: lines.join('\n'), tableMap: tableMap, tableCount: lines.length } }];

const c = $input.first().json;
let txt = '';
try { if (Array.isArray(c.content)) txt = c.content.map(x => x.text || '').join(''); } catch (e) {}
txt = String(txt).trim().replace(/^\x60{3}(?:json)?/i, '').replace(/\x60{3}$/, '').trim();
let plan = { metrics: [], skipped: [] };
try { plan = JSON.parse(txt); } catch (e) {}

const cfg = $('⚙️ Config').first().json;
const tableMap = $('🧩 Read Schema').first().json.tableMap || {};
const base = String(cfg.supabaseUrl).replace(/\/$/, '') + '/rest/v1/';
const now = Date.now(); const H = 3600 * 1000; const D = 24 * H;
const iso = ms => new Date(ms).toISOString();
const ph = {
  SINCE_WINDOW: iso(now - (Number(cfg.windowHours || 24)) * H),
  SINCE_24H: iso(now-24*H), SINCE_48H: iso(now-48*H), SINCE_72H: iso(now-72*H),
  SINCE_7D: iso(now-7*D), SINCE_30D: iso(now-30*D), SINCE_31D: iso(now-31*D), SINCE_90D: iso(now-90*D), NOW: iso(now)
};
const resolve = s => { let out = String(s || ''); for (const k of Object.keys(ph)) { out = out.split(k).join(ph[k]); } return out; };

const skipped = Array.isArray(plan.skipped) ? plan.skipped.slice() : [];
const out = [];
for (const m of (plan.metrics || [])) {
  if (!m || !m.table || !tableMap[m.table]) { skipped.push({ requested: (m && m.label) || '(unknown)', reason: 'table not in your database' }); continue; }
  let q = resolve(m.query || '');
  if (q && q[0] === '?') q = q.slice(1);
  const url = base + m.table + '?' + (q ? q + '&' : '') + 'limit=10000';
  out.push({ json: { id: m.id || m.label, label: m.label || m.id || m.table, op: m.op || 'count', value_column: m.value_column || null, group_column: m.group_column || null, url: url, skipped: skipped } });
}
if (out.length === 0) { out.push({ json: { dummy: true, url: base, op: 'count', label: 'none', skipped: skipped } }); }
return out;

const metrics = $('✅ Validate & Resolve').all().map(i => i.json);
const resp = $('🔎 Run Query').all().map(i => i.json);
const results = [];
for (let i = 0; i < metrics.length; i++) {
  const m = metrics[i];
  if (m.dummy) continue;
  const r = resp[i] || {};
  const rows = (r && Array.isArray(r.body)) ? r.body : (Array.isArray(r) ? r : []);
  let value;
  if (m.op === 'sum') {
    value = Math.round(rows.reduce(function (s, x) { return s + Number((x && x[m.value_column]) || 0); }, 0));
  } else if (m.op === 'group') {
    const pm = {}; const gc = String(m.group_column || '');
    for (const x of rows) { let v = x; for (const part of gc.split('.')) { v = (v && typeof v === 'object') ? v[part] : undefined; } const key = (v == null ? 'Unknown' : String(v)); pm[key] = (pm[key] || 0) + 1; }
    value = Object.keys(pm).map(function (k) { return { key: k, count: pm[k] }; }).sort(function (a, b) { return b.count - a.count; }).slice(0, 5);
  } else { value = rows.length; }
  results.push({ id: m.id, label: m.label, op: m.op, value: value });
}
const skipped = (metrics[0] && metrics[0].skipped) || [];
return [{ json: { requirements: $('⚙️ Config').first().json.requirements, results: results, skipped: skipped, resultCount: results.length } }];

const r = $input.first().json;
let t = '';
try { if (Array.isArray(r.content)) t = r.content.map(c => c.text || '').join(''); } catch (e) {}
t = String(t).trim().replace(/^\x60{3}(?:json)?/i, '').replace(/\x60{3}$/, '').trim();
let o = { headline: 'Your daily pulse', summary: '', insights: [] };
try { const j = JSON.parse(t); o.headline = j.headline || o.headline; o.summary = j.summary || ''; o.insights = Array.isArray(j.insights) ? j.insights : []; } catch (e) {}
return [{ json: o }];

const data = $('🧮 Collect Results').first().json;
const rep = $input.first().json;
const cfg = $('⚙️ Config').first().json;
const fmt = function (v) { return (v == null ? '0' : String(v)); };
let cards = '';
for (const m of (data.results || [])) {
  let val = (m.op === 'group')
    ? (Array.isArray(m.value) ? m.value.map(function (g) { return g.key + ': <b>' + g.count + '</b>'; }).join('<br>') : '')
    : '<b>' + fmt(m.value) + '</b>';
  cards += '<tr><td style="padding:10px 0;border-bottom:1px solid #eee;color:#374151;font-size:14px;vertical-align:top">' + m.label + '</td><td style="padding:10px 0;border-bottom:1px solid #eee;text-align:right;color:#111827;font-size:14px">' + val + '</td></tr>';
}
const skipped = (data.skipped || []).map(function (s) { return '<li>' + s.requested + ' — ' + s.reason + '</li>'; }).join('');
const insights = (rep.insights || []).map(function (s) { return '<li style="margin-bottom:4px">' + s + '</li>'; }).join('');
const html = '<!DOCTYPE html><html><body style="margin:0;background:#f4f4f5;font-family:Arial,Helvetica,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="padding:24px 0"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;background:#fff;border-radius:12px;overflow:hidden"><tr><td style="background:#111827;padding:20px 28px;color:#fff;font-size:18px;font-weight:bold">' + cfg.brandName + ' — Daily Pulse</td></tr><tr><td style="padding:24px 28px"><h2 style="margin:0 0 6px;color:#111827;font-size:18px">' + (rep.headline || '') + '</h2><p style="margin:0 0 16px;color:#374151;line-height:1.6;font-size:14px">' + (rep.summary || '') + '</p><table width="100%" cellspacing="0">' + cards + '</table>' + (insights ? ('<h3 style="margin:20px 0 6px;font-size:14px;color:#111827">Things to note</h3><ul style="margin:0;padding-left:18px;color:#374151;font-size:14px">' + insights + '</ul>') : '') + (skipped ? ('<p style="margin:16px 0 4px;font-size:12px;color:#9ca3af">Asked for but not in your database (skipped):</p><ul style="margin:0;padding-left:18px;color:#9ca3af;font-size:12px">' + skipped + '</ul>') : '') + '</td></tr><tr><td style="padding:16px 28px;background:#f9fafb;color:#9ca3af;font-size:12px">Generated by ' + cfg.brandName + '</td></tr></table></td></tr></table></body></html>';
let lines = '';
for (const m of (data.results || [])) { lines += m.label + ': ' + (m.op === 'group' ? (Array.isArray(m.value) ? m.value.map(function (g) { return g.key + '=' + g.count; }).join(', ') : '') : fmt(m.value)) + '\n'; }
return [{ json: { to: cfg.reportEmail, subject: cfg.brandName + ' — Daily Pulse', html: html, text: (rep.headline || 'Daily Pulse') + '\n\n' + (rep.summary || '') + '\n\n' + lines } }];

const data = $('🧮 Collect Results').first().json;
const cfg = $('⚙️ Config').first().json;
const skipped = (data.skipped || []).map(function (s) { return '<li>' + s.requested + ' — ' + s.reason + '</li>'; }).join('') || '<li>(nothing matched your requirement)</li>';
const text = "The Daily Pulse ran, but none of the tables your requirement asked for were found, so there's nothing to report.\n\nLikely causes:\n1) Table names in your requirement don't match your schema.\n2) Tables exist but the API can't see them - run  NOTIFY pgrst, 'reload schema';  in Supabase, then retry.\n3) Wrong Supabase API credential / project URL.";
const html = "<!DOCTYPE html><html><body style='font-family:Arial,Helvetica,sans-serif;background:#f4f4f5;margin:0;padding:24px'><table width='600' align='center' cellpadding='0' cellspacing='0' style='background:#fff;border-radius:12px;overflow:hidden'><tr><td style='background:#b45309;color:#fff;padding:20px 28px;font-size:18px;font-weight:bold'>" + cfg.brandName + " — no matching data for your requirement</td></tr><tr><td style='padding:24px 28px;color:#374151;font-size:14px;line-height:1.6'>The Pulse ran, but <b>none of the tables your requirement asked for were found</b>.<br><br><b>Asked for but not found:</b><ul>" + skipped + "</ul><b>How to fix:</b><ul><li>Match the table names in your requirement to your schema</li><li>If the tables exist, run <code>NOTIFY pgrst, 'reload schema';</code> then retry</li><li>Check the Supabase API credential + project URL</li></ul></td></tr></table></body></html>";
return [{ json: { to: cfg.reportEmail, subject: cfg.brandName + " — no matching data for your requirement", html: html, text: text } }];
